import React from 'react';

const LOGO_BASE64 = "data:image/png;base64,";

interface BrandLogoProps {
  variant?: 'full' | 'icon-only' | 'header' | 'login';
  className?: string;
  iconSize?: 'sm' | 'md' | 'lg' | 'xl' | '2xl';
  size?: 'sm' | 'md' | 'lg' | 'xl' | '2xl';
  theme?: 'dark' | 'light';
}

export function BrandLogo({
  variant = 'icon-only',
  className = '',
  iconSize,
  size,
  theme,
}: BrandLogoProps) {

  const isDark = theme === 'dark';

  const sizeClasses = {
    sm: 'w-8 h-8',
    md: 'w-12 h-12',
    lg: 'w-16 h-16',
    xl: 'w-20 h-20',
    '2xl': 'w-28 h-28'
  };

  const selectedSize = sizeClasses[iconSize || size || 'md'];

  const logoIcon = (
    <img
      src={LOGO_BASE64}
      alt="Pau Brasil Distribuidora Ambev"
      className={`${selectedSize} shrink-0 object-contain`}
    />
  );

  if (variant === 'icon-only') {
    return logoIcon;
  }

  if (variant === 'login') {
    return (
      <div className={`flex items-center space-x-3.5 ${className}`} id="brand_logo_login">
        <div className="bg-[#f0f4ff]/90 p-2 rounded-[14px] flex items-center justify-center shrink-0 border border-blue-100/70 shadow-[0_4px_12px_rgba(30,86,240,0.03)]">
          <img
            src={LOGO_BASE64}
            alt="Pau Brasil Distribuidora Ambev"
            className="w-10 h-10 shrink-0 object-contain"
          />
        </div>
        <div className="flex items-center space-x-3.5 select-none leading-none">
          <span className={`font-sans font-medium text-2xl tracking-tight text-slate-700`}>
            PAU
          </span>
          <div className="h-6 w-[1px] bg-blue-200" />
          <span className={`font-sans font-black text-2xl tracking-tight text-[#1e56f0]`}>
            BRASIL
          </span>
        </div>
      </div>
    );
  }

  if (variant === 'header') {
    return (
      <div className={`flex items-center space-x-3 ${className}`} id="brand_logo_header">
        <div className="bg-white p-1.5 rounded-lg flex items-center justify-center shrink-0 border border-slate-100 shadow-sm">
          {logoIcon}
        </div>
        <div className="leading-tight">
          <span className={`font-sans font-black text-base tracking-tight block uppercase ${isDark ? 'text-white' : 'text-slate-900'}`}>
            <span className={isDark ? 'text-blue-400' : 'text-[#1e56f0]'}>PAU</span> <span className={isDark ? 'text-white' : 'text-slate-950'}>BRASIL</span>
          </span>
          <span className={`font-mono text-[9px] sm:text-[10px] tracking-[0.15em] uppercase block leading-none mt-1 ${isDark ? 'text-slate-300' : 'text-slate-500'}`}>
            distribuidora <span className={`${isDark ? 'text-blue-400' : 'text-[#1e56f0]'} font-extrabold`}>ambev</span>
          </span>
        </div>
      </div>
    );
  }

  // Default 'full' variant (horizontal logo)
  return (
    <div className={`flex items-center space-x-4 ${className}`} id="brand_logo_full">
      <div className="bg-white p-2 rounded-xl shadow-sm border border-slate-100 flex items-center justify-center shrink-0">
        {logoIcon}
      </div>
      <div className="leading-tight">
        <span className={`font-sans font-black text-2xl tracking-tight block uppercase ${isDark ? 'text-white' : 'text-slate-950'}`}>
          <span className={isDark ? 'text-blue-400' : 'text-[#1e56f0]'}>PAU</span> <span className={isDark ? 'text-white' : 'text-slate-950'}>BRASIL</span>
        </span>
        <span className={`font-sans text-[10px] uppercase font-bold tracking-[0.2em] mt-1.5 block leading-none ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>
          distribuidora <span className={`${isDark ? 'text-blue-400' : 'text-blue-600'} font-extrabold`}>ambev</span>
        </span>
      </div>
    </div>
  );
}

export default BrandLogo;
